# dual explorer-H1 · S40-T1-A-E2
def assess(record: dict) -> str:
    required = {'observed_ms', 'owner', 'environment', 'case_id', 'source', 'target_ms', 'response', 'stimulus'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (record["observed_ms"] >= record["target_ms"])
    return "PASS" if ok else 'REJECT_QA_SCENARIO'

valid = {'case_id': 'CASO-LIM-040-1A', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 280, 'target_ms': 300, 'owner': 'platform'}
invalid = {'case_id': 'CASO-LIM-040-1A', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 350, 'target_ms': 300, 'owner': 'platform'}
incomplete = {'case_id': 'CASO-LIM-040-1A', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 280, 'target_ms': 300}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

